export function gerarFuncionalidadesHTML(content: string): string {
  const lines = content.split("\n")
  const items: string[] = []

  for (const line of lines) {
    const t = line.trim()
    // Formato: "1. **Nome** — Descrição"
    const m1 = t.match(/^(\d+)\.\s+\*\*(.+?)\*\*\s*[—–:\-]\s*(.+)$/)
    if (m1) {
      items.push(`<div class="func-item"><p><strong>${m1[1]}. ${m1[2]}</strong> - ${clean(m1[3])}</p></div>`)
      continue
    }

    // Formato: "1. Nome — Descrição"
    const m2 = t.match(/^(\d+)\.\s+(.+?)\s*[—–]\s*(.+)$/)
    if (m2) {
      items.push(`<div class="func-item"><p><strong>${m2[1]}. ${m2[2]}</strong> - ${clean(m2[3])}</p></div>`)
      continue
    }

    // Formato: "- **Nome**: Descrição"
    const m3 = t.match(/^[-*•]\s+\*\*(.+?)\*\*[:\s]+(.+)$/)
    if (m3) {
      items.push(`<div class="func-item"><p><strong>${items.length + 1}. ${m3[1]}</strong> - ${clean(m3[2])}</p></div>`)
      continue
    }
  }

  // Fallback: itens simples com bullet points
  if (!items.length) {
    content.split("\n")
      .filter((l) => /^[-*•]\s/.test(l.trim()))
      .slice(0, 8)
      .forEach((l, i) => {
        items.push(`<div class="func-item"><p><strong>${i + 1}. ${clean(l.replace(/^[-*•]\s+/, ""))}</strong></p></div>`)
      })
  }

  return items.join("\n\n")
}

async function handleDownloadPDF() {
  if (sections.length === 0) return
  setDownloading(true)
  try {
    // 1. Busca o novo template finalizado
    const res = await fetch("/proposta-template.html")
    if (!res.ok) throw new Error("Template não encontrado")
    let html = await res.text()

    // 2. Constrói os tokens com o novo sistema de mapeamento
    const tokens = buildProposalTokens({ empresa, para, projeto, modeloTrabalho, dataCriacao, sections })
    console.log("[ProposalDocument] Generated tokens:", tokens)
    console.log("[ProposalDocument] Sections:", sections)

    // 3. Substitui todas as variáveis no HTML
    for (const [key, value] of Object.entries(tokens)) {
      html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value || '')
    }

    // 4. Remove variáveis não utilizadas (novo sistema de limpeza)
    html = html.replace(/\{\{[A-Z_]+\}\}/g, '')

    // 5. Abre em nova janela e dispara impressão automaticamente
    const win = window.open("", "_blank")
    if (!win) {
      toast.error("Pop-up bloqueado. Permita pop-ups para este site e tente novamente.")
      return
    }
    win.document.open()
    win.document.write(html)

