/* ── PRINT STYLES ── */
@media print {
    body {
        background: #fcfcfc;
        -webkit-print-color-adjust: exact;
        print-color-adjust: exact;
    }

    .document {
        padding: 24px 0;
        width: 100%;
        margin: 0;
        background: #fcfcfc !important;
    }

    .continuous-content {
        margin: 0 auto;
        width: 210mm;
        max-width: 210mm;
        padding: 46px 56px;
        page-break-after: auto;
        background: #fcfcfc !important;
        min-height: 297mm;
        box-shadow: 0 2px 12px rgba(0,0,0,0.12);
    }

    /* Enhanced page break controls for continuous flow */
    h2 {
        page-break-after: avoid;
        break-after: avoid;
        page-break-inside: avoid;
        break-inside: avoid;
    }
    h3 {
        page-break-after: avoid;
        break-after: avoid;
    }
    h4 {
        page-break-after: avoid;
        break-after: avoid;
    }
    .func-item {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    .team-role {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    .phase {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    .section {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    .section.allow-break {
        page-break-inside: auto;
        break-inside: auto;
    }
    .closing {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    ul, ol {
        page-break-inside: avoid;
        break-inside: avoid;
    }
    p {
        orphans: 3;
        widows: 3;
    }

    /* Continuous content background for print */
    .continuous-content::before {
        position: fixed;
        top: 0;
        left: 50%;
        transform: translateX(-50%);
        width: 210mm;
        height: 100%;
        background: url('/fundo-center.png') center center no-repeat;
        background-size: 602px auto;
        background-attachment: fixed;
        opacity: 0.035;
    }
}

@page {
    size: A4;
    margin: 56px;
    /* Rodapé com numeração à direita */
    @bottom-right {
        content: counter(page);
        font-family: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
        font-size: 13px;
        font-weight: 500;
        color: #374151;

